                <div key={t.id} style={{padding:'9px 11px',background:`${col}0d`,border:`1px solid ${col}33`,borderRadius:8,animation:'slide .3s ease'}}>
                  <div style={{display:'flex',justifyContent:'space-between',marginBottom:4}}>
